class Product:
    def __init__(self, product_id, name, price, stock):
        self.product_id = product_id
        self.name = name
        self.price = price
        self.stock = stock

    def update_stock(self, quantity):
        self.stock += quantity

    def __repr__(self):
        return f"Product({self.product_id}, {self.name}, ${self.price}, Stock: {self.stock})"

class User:
    def __init__(self, user_id, name, email):
        self.user_id = user_id
        self.name = name
        self.email = email

    def __repr__(self):
        return f"User({self.user_id}, {self.name}, {self.email})"

class Order:
    def __init__(self, order_id, user):
        self.order_id = order_id
        self.user = user
        self.items = {}  # Dictionary to store product: quantity

    def add_product(self, product, quantity):
        if product in self.items:
            self.items[product] += quantity
        else:
            self.items[product] = quantity

    def total_amount(self):
        total = 0
        for product, qty in self.items.items():
            total += product.price * qty
        return total

    def __repr__(self):
        return f"Order({self.order_id}, User: {self.user.name}, Items: {len(self.items)})"

import os

max_files = 1024  # Typical default limit on many systems
files = []

try:
    for i in range(max_files + 10):  # Try to open more files than the system limit
        f = open(f"tempfile_{i}.txt", "w")
        files.append(f)
except OSError as e:
    if "Too many open files" in str(e):
        print("Resource exhaustion detected: too many open files.")
    else:
        raise
finally:
    for f in files:
        f.close()  # Always close files to free resources

print("File handles cleaned up properly.")

